package org.eclipse.rdf4j.sail.lmdb.benchmark;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.IOException;
import java.nio.charset.StandardCharsets;
import java.nio.file.Files;
import java.nio.file.Path;
import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;
import java.util.ArrayList;
import java.util.List;
import java.util.stream.Collectors;
import java.util.stream.Stream;

import org.apache.commons.io.FileUtils;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.query.BindingSet;
import org.eclipse.rdf4j.repository.RepositoryConnection;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.rio.helpers.NTriplesUtil;
import org.eclipse.rdf4j.sail.lmdb.benchmark.FoafCliqueQueryCatalog.QueryScenario;
import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.TestInstance;
import org.junit.jupiter.params.ParameterizedTest;
import org.junit.jupiter.params.provider.Arguments;
import org.junit.jupiter.params.provider.MethodSource;

/**
 * Parity harness for the FOAF-clique catalog: every query must produce the identical result multiset under the native
 * engine (with and without WCOJ) and the generic RDF4J evaluator. One store is shared; the engine is switched per run
 * through the same system properties the benchmark uses, saving and restoring the previous values.
 */
@TestInstance(TestInstance.Lifecycle.PER_CLASS)
class FoafCliqueCorrectnessTest {

	private static final int PEOPLE_COUNT = 300;
	private static final int CLIQUE_PERCENTAGE = 30;
	private static final int MIN_CLIQUE_SIZE = 3;
	private static final int MAX_CLIQUE_SIZE = 6;
	private static final int RANDOM_KNOWS_EDGES = 900;
	private static final long SEED = 12345L;

	private static final String NATIVE_FLAG = "rdf4j.lmdb.nativeQueryEngine.enabled";
	private static final String WCOJ_FLAG = "rdf4j.lmdb.wcoj.enabled";

	private Path tempDir;
	private SailRepository repository;

	@BeforeAll
	void setUp() throws IOException {
		tempDir = Files.createTempDirectory("rdf4j-lmdb-foaf-clique-correctness");
		repository = FoafCliqueQueryBenchmark.createRepository(tempDir.toFile());
		repository.init();
		try (SailRepositoryConnection connection = repository.getConnection()) {
			new FoafCliqueDataGenerator(PEOPLE_COUNT, CLIQUE_PERCENTAGE, MIN_CLIQUE_SIZE, MAX_CLIQUE_SIZE,
					RANDOM_KNOWS_EDGES, SEED).populate(connection);
		}
	}

	@AfterAll
	void tearDown() throws IOException {
		if (repository != null) {
			repository.shutDown();
		}
		if (tempDir != null) {
			FileUtils.deleteDirectory(tempDir.toFile());
		}
	}

	@ParameterizedTest(name = "{0} / {1}")
	@MethodSource("queryAndModeArguments")
	void eachQueryAndModeShouldProduceTheSameResultHash(QueryScenario scenario, String engineMode) {
		String expected = inEngineMode(FoafCliqueQueryBenchmark.MODE_GENERIC,
				() -> executeResultSetHash(scenario.query()));
		String actual = inEngineMode(engineMode, () -> executeResultSetHash(scenario.query()));
		assertEquals(expected, actual,
				engineMode + " must preserve the full result set for " + scenario.benchmarkMethodName());
	}

	static Stream<Arguments> queryAndModeArguments() {
		return FoafCliqueQueryCatalog.allScenarios()
				.stream()
				.flatMap(scenario -> FoafCliqueQueryBenchmark.engineModes()
						.stream()
						.map(engineMode -> Arguments.of(scenario, engineMode)));
	}

	private <T> T inEngineMode(String engineMode, java.util.function.Supplier<T> action) {
		String previousNative = System.getProperty(NATIVE_FLAG);
		String previousWcoj = System.getProperty(WCOJ_FLAG);
		try {
			FoafCliqueQueryBenchmark.applyEngineMode(engineMode);
			return action.get();
		} finally {
			restore(NATIVE_FLAG, previousNative);
			restore(WCOJ_FLAG, previousWcoj);
		}
	}

	private static void restore(String key, String previous) {
		if (previous == null) {
			System.clearProperty(key);
		} else {
			System.setProperty(key, previous);
		}
	}

	private String executeResultSetHash(String query) {
		List<String> rows = new ArrayList<>();
		try (RepositoryConnection connection = repository.getConnection()) {
			connection.prepareTupleQuery(query)
					.evaluate()
					.forEach(bindingSet -> rows.add(bindingSetToString(bindingSet)));
		}
		rows.sort(String::compareTo);
		return hash(rows);
	}

	private String bindingSetToString(BindingSet bindingSet) {
		return bindingSet.getBindingNames()
				.stream()
				.sorted()
				.map(name -> name + "=" + valueToString(bindingSet.getValue(name)))
				.collect(Collectors.joining("|"));
	}

	private String valueToString(Value value) {
		return NTriplesUtil.toNTriplesString(value);
	}

	private String hash(List<String> rows) {
		MessageDigest digest = newSha256Digest();
		for (String row : rows) {
			digest.update(row.getBytes(StandardCharsets.UTF_8));
			digest.update((byte) '\n');
		}
		return toHex(digest.digest());
	}

	private MessageDigest newSha256Digest() {
		try {
			return MessageDigest.getInstance("SHA-256");
		} catch (NoSuchAlgorithmException e) {
			throw new IllegalStateException("Missing SHA-256 digest", e);
		}
	}

	private String toHex(byte[] bytes) {
		StringBuilder builder = new StringBuilder(bytes.length * 2);
		for (byte b : bytes) {
			builder.append(Character.forDigit((b >>> 4) & 0x0F, 16));
			builder.append(Character.forDigit(b & 0x0F, 16));
		}
		return builder.toString();
	}
}
